def select_next_node(current_node, truck_nodes, depot_node, unvisited_nodes, distance_matrix):
    if len(unvisited_nodes) == 0:
        if current_node != depot_node:
            return depot_node
        return None

    available_nodes = [node for node in unvisited_nodes if node not in truck_nodes]

    if not available_nodes:
        return None

    def calculate_angle(node1, node2, node3):
        v1 = np.array([distance_matrix[node1, node2]])
        v2 = np.array([distance_matrix[node1, node3]])
        cos_angle = np.dot(v1, v2) / (np.linalg.norm(v1) * np.linalg.norm(v2) + 1e-5)
        return np.arccos(min(1.0, max(-1.0, cos_angle)))

    best_value = float('inf')
    next_node = None

    for node in available_nodes:
        distance_to_node = distance_matrix[current_node, node]
        angle = calculate_angle(depot_node, current_node, node)
        value = distance_to_node * angle

        if value < best_value:
            best_value = value
            next_node = node

    return next_node

